import axios from 'axios';
import { logger } from '../utils/logger';

interface WebhookConfig {
  url: string;
  secret: string;
  events: string[];
}

export class WebhookService {
  async testWebhook(config: WebhookConfig): Promise<{ status: number; body: string }> {
    logger.info(`Testing webhook endpoint: ${config.url}`);

    try {
      const response = await axios.post(config.url, {
        event: 'test',
        timestamp: new Date().toISOString(),
      }, {
        headers: {
          'Content-Type': 'application/json',
          'X-Webhook-Secret': config.secret,
        },
        timeout: 10000,
      });

      return { status: response.status, body: JSON.stringify(response.data) };
    } catch (error: any) {
      return { status: error.response?.status || 0, body: error.message };
    }
  }

  async fetchRemoteConfig(configUrl: string): Promise<Record<string, unknown>> {
    const response = await axios.get(configUrl);
    return response.data;
  }
}
